def q(topic, qtype, question, options, answer, explanation, code=None):
    item = {
        "topic": topic,
        "type": qtype,
        "question": question,
        "options": options,
        "answer": answer,
        "explanation": explanation,
    }
    if code:
        item["code"] = code
    return item


