PHASES = {
    "phase-06.json": PHASE_06,
    "phase-07.json": PHASE_07,
    "phase-08.json": PHASE_08,
    "phase-09.json": PHASE_09,
}


def main():
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    for filename, questions in PHASES.items():
        assert len(questions) == 42, f"{filename}: expected 42, got {len(questions)}"
        path = DATA_DIR / filename
        with path.open("w", encoding="utf-8") as f:
            json.dump({"questions": questions}, f, indent=2, ensure_ascii=False)
            f.write("\n")
        print(f"Wrote {path} ({len(questions)} questions)")


if __name__ == "__main__":
    main()
